mapper.select:
SELECT 
FROM tb_vehicle_part t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.vin = #{vin}


    AND t.part_id = #{partId}


    AND t.vehicle_node_code = #{vehicleNodeCode}


    AND t.bind_state = #{bindState}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

SELECT FROM tb_vehicle_part t WHERE t.row_valid = 1
AND t.vin = #{vin}
AND EXISTS (SELECT 1 FROM tb_part_info pi WHERE pi.id = t.part_id AND pi.part_code = #{pn})
AND t.bind_state = #{bindState}
ORDER BY t.id DESC
